import heapq

def nth_super_ugly_number(n, primes):
    ugly_numbers = [1]
    heap = [(prime, prime) for prime in primes]
    heapq.heapify(heap)
    for _ in range(n - 1):
        _, next_ugly = heapq.heappop(heap)
        ugly_numbers.append(next_ugly)
        for prime in primes:
            if next_ugly % prime == 0:
                heapq.heappush(heap, (prime * next_ugly, prime * next_ugly))
                break
    return ugly_numbers[-1]

